Pass the comparison table element to `setExpanded` so the button receives `aria-controls` pointing at the table’s `id`, e.g.:  
```js
function setComparisonTableExpanded(expanded) {
  const table   = qs('[data-pricing-comparison], .pricing-comparison');
  const trigger = qs('[data-expand-comparison]');
  if (!table) return;

  if (expanded) {
    table.removeAttribute('hidden');
    setExpanded(trigger, true, table);   // ← add panel argument
    liveRegion.announce(STRINGS.comparisonTableExpanded || 'Comparison table expanded');
  } else {
    table.setAttribute('hidden', '');
    setExpanded(trigger, false, table);   // ← add panel argument
  }
}
```

